using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class TimeTrackingTraining : TrainingContentBase
{
    public TimeTrackingTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Time Tracking Overview",
            Slug = "time-tracking-overview",
            Summary = "What time tracking does, how timers and manual entries work, clock events, job linking, and how time data connects to payroll and costing.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/time-tracking"]""",
            Tags = """["time-tracking","timers"]""",
            ContentJson = """{"body":"## Time Tracking Overview\n\nThe Time Tracking module records how employees spend their working hours. It supports two methods of capturing time — live timers and manual entries — and integrates with clock events, jobs, payroll, and cost accounting.\n\n### Two Ways to Track Time\n\n**Live Timers:** Click Start Timer to begin tracking time in real time. The timer runs until you click Stop Timer. The elapsed duration is calculated automatically from the start and stop timestamps. Timers sync across browser tabs and devices via SignalR — if you start a timer on your phone, your desktop shows it running immediately.\n\n**Manual Entries:** Click Manual Entry to log time after the fact. You enter the date, hours, minutes, an optional category, and optional notes. Manual entries are marked with an edit_note icon in the table to distinguish them from timer-based entries.\n\n### Categories\n\nEvery time entry (timer or manual) can be tagged with a category:\n- **Production** — direct production work on a job\n- **Setup** — machine setup, tooling changes, fixture preparation\n- **Inspection** — quality checks, measurements, first-article inspection\n- **Maintenance** — equipment maintenance, cleaning, calibration\n- **Training** — learning, onboarding, skill development\n- **Meeting** — team meetings, planning sessions, standups\n- **Admin** — paperwork, emails, administrative tasks\n- **Cleanup** — end-of-shift cleanup, organizing\n- **Other** — anything that doesn't fit the above\n\nCategories are optional but recommended — they feed into reports and help managers understand how time is distributed across activities.\n\n### Clock Events\n\nClock events are separate from time entries. They record when an employee clocks in or out of the facility using an RFID badge, barcode scan, or manual entry on the shop floor kiosk. Clock events track:\n- **Event type** — clock-in, clock-out, break-start, break-end (driven by reference data)\n- **Timestamp** — when the event occurred\n- **Scan method** — how the employee identified themselves (RFID, barcode, manual)\n- **Source** — which device or kiosk recorded the event\n- **Reason** — optional note (e.g., 'early departure — appointment')\n\nClock events establish the employee's presence on-site. Time entries track what they worked on during that presence.\n\n### Job Linking\n\nTime entries can be linked to a specific job. When a timer is started from a job's detail panel on the kanban board, the job association is set automatically. This connects time directly to job costing — the labor cost for each entry is calculated from the employee's rate and applied to the job's cost rollup.\n\n### Date Range Filtering\n\nThe time tracking page has From and To date pickers that filter the entries table. A summary line shows the total hours and entry count for the current filter. When no dates are set, recent entries are shown.\n\n### Locking and Editability\n\nTime entries can be locked by a manager or by pay period closure. Locked entries show a lock icon and cannot be edited or deleted. Unlocked entries from today or future dates can be deleted; past entries require an admin time correction (which creates an audit trail).\n\n### Admin Time Corrections\n\nManagers and admins can correct time entries via the Admin > Time Corrections page. Corrections require a reason and create a TimeCorrectionLog entry that preserves the original values for audit purposes. Fields that can be corrected include date, duration, start/end times, category, notes, and job assignment.\n\n### Pay Periods and Overtime\n\nTime entries roll up into pay periods (weekly, bi-weekly, semi-monthly, or monthly — configurable in admin settings). When a pay period is locked, all entries within that period become read-only. Overtime rules can be configured (e.g., >40 hours/week = 1.5x) and the system calculates overtime breakdowns per employee per week.\n\n### SignalR Real-Time Sync\n\nTimer start and stop events broadcast via SignalR's TimerHub. If two browser tabs are open, starting a timer in one tab updates the other tab's display immediately. The page header dynamically switches between Start Timer and Stop Timer buttons based on whether a timer is currently active.\n\n### Connection to Payroll\n\nTime entries feed into payroll calculations. Each entry's labor cost is computed from the employee's hourly rate multiplied by the duration. Burden cost (overhead allocation) is tracked separately. When QuickBooks integration is active, time entries can sync as Time Activities to the accounting system via the AccountingTimeActivityId field.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Time Tracking — Guided Tour",
            Slug = "time-tracking-walkthrough",
            Summary = "A guided tour of the time tracking page: starting and stopping timers, logging manual entries, filtering by date, and reading the data table.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/time-tracking"]""",
            Tags = """["time-tracking","walkthrough","timers"]""",
            ContentJson = """{"appRoute":"/time-tracking","startButtonLabel":"Tour Time Tracking","steps":[{"element":"[data-testid='start-timer-btn']","popover":{"title":"Start Timer","description":"Click here to start a live timer. A dialog opens where you can optionally select a category and add notes. Once started, the button changes to Stop Timer with the elapsed time displayed. The timer runs server-side, so it persists across page refreshes and browser tabs.","side":"bottom"}},{"element":"[data-testid='manual-entry-btn']","popover":{"title":"Manual Entry","description":"Click here to log time after the fact. You'll enter a date, hours, minutes, optional category, and optional notes. Manual entries are marked with an edit icon in the table to distinguish them from timer-based entries.","side":"bottom"}},{"element":".filters-bar app-datepicker:first-of-type","popover":{"title":"From Date Filter","description":"Set the start date to filter time entries. Only entries on or after this date will appear in the table below. Leave blank to show all recent entries.","side":"bottom"}},{"element":".filters-bar app-datepicker:last-of-type","popover":{"title":"To Date Filter","description":"Set the end date to filter time entries. Only entries on or before this date will appear. Use From and To together to view a specific date range — a single day, a week, or a pay period.","side":"bottom"}},{"element":".filter-summary","popover":{"title":"Summary Line","description":"Shows the total hours and number of entries for the current filter. For example: '12.5 hours across 8 entries'. Updates automatically when you change the date filters or when new entries are added.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Time Entries Table","description":"All time entries for the current filter are listed here. Columns include an icon (timer or manual), date, user name, linked job number, category, duration (or 'Running' for active timers), notes, type badge (Timer/Manual), and an actions column. Click column headers to sort. Active timer rows are highlighted.","side":"top"}},{"element":".entry-type","popover":{"title":"Entry Type Badge","description":"Each entry shows either 'Timer' (blue) or 'Manual' (gray) to indicate how the time was recorded. Timer entries have precise start/stop timestamps; manual entries have a user-entered duration.","side":"left"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Time Tracking Field Reference",
            Slug = "time-tracking-field-reference",
            Summary = "Complete reference for every field, button, column, validation rule, and action in the Time Tracking module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/time-tracking"]""",
            Tags = """["time-tracking","reference","timers"]""",
            ContentJson = """{"title":"Time Tracking Field Reference","groups":[{"heading":"Start Timer Dialog Fields","items":[{"label":"Category (optional)","value":"Dropdown: None, Production, Setup, Inspection, Maintenance, Training, Meeting, Admin, Cleanup, Other. Tags the timer session with a work category. Default: None."},{"label":"Notes (optional)","value":"Textarea (2 rows). Free-form notes about what you're working on. Can be updated when stopping the timer."}]},{"heading":"Stop Timer Dialog Fields","items":[{"label":"Timer Running For (display)","value":"Shows elapsed time (e.g., '1h 23m') and the category if one was set when starting. Read-only informational text."},{"label":"Notes (optional)","value":"Textarea (2 rows). Additional notes to append or update when stopping the timer. Labeled 'Notes (optional)'."}]},{"heading":"Manual Entry Dialog Fields","items":[{"label":"Date (required)","value":"Datepicker. The date this time was worked. Defaults to today. data-testid: time-entry-date"},{"label":"Category (optional)","value":"Dropdown: same options as timer category. Default: None. data-testid: time-entry-category"},{"label":"Hours (required)","value":"Number input. Whole hours worked (0–24). Combined with Minutes to calculate total duration. data-testid: time-entry-hours"},{"label":"Minutes (required)","value":"Number input. Additional minutes worked (0–59). Combined with Hours. Total duration must be > 0. data-testid: time-entry-minutes"},{"label":"Notes (optional)","value":"Textarea (3 rows). Free-form description of the work performed. data-testid: time-entry-notes"}]},{"heading":"Date Filter Controls","items":[{"label":"From","value":"Datepicker in the filter bar. Filters entries to those on or after this date. Leave blank for no lower bound."},{"label":"To","value":"Datepicker in the filter bar. Filters entries to those on or before this date. Leave blank for no upper bound."},{"label":"Summary line","value":"Displays total hours (to 1 decimal) and entry count for the current filter. Example: '12.5 hours across 8 entries'."}]},{"heading":"Data Table Columns","items":[{"label":"Icon (first column)","value":"Shows entry type icon: spinning timer icon for active timers, static timer icon for completed timers, edit_note icon for manual entries. Width: 32px."},{"label":"Date","value":"Sortable. The date the time was worked, formatted MM/dd/yyyy. Type: date."},{"label":"User","value":"Sortable. The employee's display name (Last, First MI format)."},{"label":"Job","value":"The linked job number, shown as a badge. Dash (—) if no job is linked."},{"label":"Category","value":"Sortable. The work category tag (Production, Setup, etc.) or dash if none."},{"label":"Duration","value":"Sortable. Formatted as 'Xh Ym' (e.g., '2h 15m' or '45m'). Active timers show a green 'Running' badge instead."},{"label":"Notes","value":"Truncated notes text. Muted color for readability."},{"label":"Type","value":"Badge showing 'Timer' (blue) or 'Manual' (gray). Width: 80px."},{"label":"Actions","value":"Delete button (trash icon) for editable entries. Lock icon for locked or past entries. Width: 64px, right-aligned."}]},{"heading":"Clock Event Fields","items":[{"label":"Event Type Code","value":"Reference-data-driven code from the 'clock_event_type' group. Common values: clock-in, clock-out, break-start, break-end."},{"label":"Timestamp","value":"DateTimeOffset — when the event occurred. Stored in UTC."},{"label":"Scan Method","value":"How the employee identified: RFID, barcode, manual, NFC. Optional."},{"label":"Source","value":"Which device/kiosk recorded the event (e.g., 'shop-floor-kiosk-1'). Optional."},{"label":"Reason","value":"Optional note explaining the event (e.g., 'early departure — doctor appointment')."}]},{"heading":"Time Entry Entity Fields (Backend)","items":[{"label":"JobId","value":"Optional FK to the Job entity. Links the time entry to a specific job for costing."},{"label":"UserId","value":"FK to the user who owns this time entry. Set automatically from the authenticated user."},{"label":"Date","value":"DateOnly — the work date. Used for filtering and pay period grouping."},{"label":"DurationMinutes","value":"Integer — total minutes worked. For timer entries, calculated from TimerStop - TimerStart."},{"label":"TimerStart / TimerStop","value":"DateTimeOffset — precise start and stop timestamps for timer entries. Null for manual entries."},{"label":"IsManual","value":"Boolean — true for manual entries, false for timer entries. Drives the Type badge display."},{"label":"IsLocked","value":"Boolean — true when locked by a manager or pay period closure. Prevents edits and deletes."},{"label":"OperationId","value":"Optional FK to Operation — for operation-level time tracking within a job."},{"label":"EntryType","value":"Enum: Run (default), Setup. Distinguishes direct production time from setup time."},{"label":"LaborCost","value":"Decimal — calculated labor cost (employee rate x duration). Used in job costing."},{"label":"BurdenCost","value":"Decimal — overhead/burden allocation for this entry."},{"label":"AccountingTimeActivityId","value":"External ID from QuickBooks when synced as a Time Activity. Null if not synced."}]},{"heading":"Admin Time Correction Fields","items":[{"label":"Date","value":"Optional corrected date (overrides original)."},{"label":"DurationMinutes","value":"Optional corrected duration in minutes."},{"label":"Start Time / End Time","value":"Optional corrected start/end timestamps."},{"label":"Category","value":"Optional corrected category."},{"label":"Notes","value":"Optional corrected notes."},{"label":"Job","value":"Optional corrected job assignment (JobId)."},{"label":"Reason (required)","value":"Why this correction was made. Stored in TimeCorrectionLog for audit trail. Required field."}]},{"heading":"Buttons and Actions","items":[{"label":"Start Timer (primary button)","value":"Opens the start timer dialog. Only visible when no timer is active. data-testid: start-timer-btn"},{"label":"Stop Timer (warn button)","value":"Opens the stop timer dialog showing elapsed time. Only visible when a timer is running. Replaces Start Timer. data-testid: stop-timer-btn"},{"label":"Manual Entry (secondary button)","value":"Opens the manual time entry dialog with draft auto-save support. data-testid: manual-entry-btn"},{"label":"Log Entry (dialog save)","value":"Saves the manual entry. Disabled when form is invalid or saving is in progress. Shows validation popover on hover when invalid. data-testid: time-entry-save-btn"},{"label":"Start (timer dialog)","value":"Starts the timer with optional category and notes. data-testid: timer-start-btn"},{"label":"Stop Timer (stop dialog)","value":"Stops the active timer. Calculates duration from elapsed time. data-testid: timer-stop-btn"},{"label":"Delete (row action)","value":"Deletes an unlocked, editable time entry after confirmation dialog. Only available for today's or future entries."},{"label":"Cancel (all dialogs)","value":"Closes the dialog without saving."}]},{"heading":"Validation Rules","items":[{"label":"Manual Entry — Date","value":"Required. Must select a date."},{"label":"Manual Entry — Hours","value":"Required. Must be between 0 and 24."},{"label":"Manual Entry — Minutes","value":"Required. Must be between 0 and 59."},{"label":"Manual Entry — Total Duration","value":"Hours + Minutes must be greater than 0. The save button checks this before submitting."},{"label":"Timer — Start","value":"Cannot start a new timer while one is already running. The Start Timer button is hidden when a timer is active."},{"label":"Delete — Editability","value":"Only unlocked entries from today or future dates can be deleted. Past entries show a lock icon."},{"label":"Admin Correction — Reason","value":"Required. Must explain why the correction was made."}]},{"heading":"Real-Time Sync (SignalR)","items":[{"label":"TimerHub","value":"SignalR hub at /hubs/timer. Broadcasts timer start and stop events."},{"label":"onTimerStartedEvent","value":"Fires when any user starts a timer. Triggers a full reload of the entries table."},{"label":"onTimerStoppedEvent","value":"Fires when any user stops a timer. Triggers a full reload of the entries table."},{"label":"Active timer indicator","value":"The page header dynamically switches between Start Timer (green) and Stop Timer (orange) based on whether the current user has an active timer."},{"label":"Cross-tab sync","value":"Starting or stopping a timer in one browser tab is reflected in all other open tabs within seconds via SignalR."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Time Tracking Knowledge Check",
            Slug = "time-tracking-quiz",
            Summary = "Test your knowledge of time tracking: timers, manual entries, clock events, job linking, locking, corrections, and real-time sync.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["time-tracking","timers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"tt1","text":"You need to track time for a 2-hour machine setup that happened yesterday. What is the correct approach?","options":[{"id":"a","text":"Start a timer now and stop it after 2 hours"},{"id":"b","text":"Click Manual Entry, set the date to yesterday, enter 2 hours and 0 minutes, and select the Setup category","isCorrect":true},{"id":"c","text":"Ask your manager to add it via the Admin panel"},{"id":"d","text":"Create a clock event with type 'setup' and a 2-hour duration"}],"explanation":"Manual entries are for logging time after the fact. Set the date to when the work was done, enter the duration in hours and minutes, and optionally select a category. Timer entries are for real-time tracking only."},{"id":"tt2","text":"You started a timer 45 minutes ago and need to stop it. Where do you find the stop button?","options":[{"id":"a","text":"In the same location as the Start Timer button — it changes to Stop Timer when a timer is running","isCorrect":true},{"id":"b","text":"Right-click the active timer row in the table and select Stop"},{"id":"c","text":"Open the manual entry dialog and click Stop Active Timer"},{"id":"d","text":"Navigate to Admin > Time Tracking > Active Timers"}],"explanation":"The Start Timer button in the page header dynamically changes to a Stop Timer button (with elapsed time displayed) whenever a timer is running. Click it to open the stop dialog."},{"id":"tt3","text":"What is the difference between a time entry and a clock event?","options":[{"id":"a","text":"They are the same thing — clock events are just time entries from the shop floor"},{"id":"b","text":"Time entries record what work was done and for how long; clock events record when an employee arrived at or left the facility","isCorrect":true},{"id":"c","text":"Clock events track machine uptime; time entries track human labor"},{"id":"d","text":"Time entries are for salaried employees; clock events are for hourly workers"}],"explanation":"Time entries track work duration and can be linked to jobs and categories. Clock events track facility presence — when someone clocked in, clocked out, or took breaks. They serve different purposes but complement each other."},{"id":"tt4","text":"A time entry in the table shows a lock icon instead of a delete button. What does this mean?","options":[{"id":"a","text":"The entry is linked to a job and cannot be modified without unlinking it first"},{"id":"b","text":"The entry is either locked by a manager/pay period or is a past-date entry that requires an admin correction to change","isCorrect":true},{"id":"c","text":"The entry has been synced to QuickBooks and is waiting for confirmation"},{"id":"d","text":"The entry belongs to another user and you don't have permission to delete it"}],"explanation":"The lock icon appears when an entry is locked (by a manager or pay period closure) or when it's a past-date entry. Only today's or future unlocked entries can be deleted directly. Past entries require an admin time correction."},{"id":"tt5","text":"You want to see only the time entries from the first week of March. How do you filter the table?","options":[{"id":"a","text":"Type '03/01' into the search box in the page header"},{"id":"b","text":"Set the From date to 03/01 and the To date to 03/07 using the date pickers in the filter bar","isCorrect":true},{"id":"c","text":"Click the Date column header and select the date range from the dropdown"},{"id":"d","text":"Go to Reports > Time Report and set the date range there"}],"explanation":"The filter bar has From and To date pickers. Set From to the start date and To to the end date. The table and summary line update automatically to show only entries within that range."},{"id":"tt6","text":"An active timer entry shows 'Running' in green in the Duration column. What happens if you close the browser and reopen the time tracking page?","options":[{"id":"a","text":"The timer is lost — you need to manually add the time"},{"id":"b","text":"The timer is still running because it tracks server-side start time; the elapsed time recalculates from the stored TimerStart timestamp","isCorrect":true},{"id":"c","text":"The timer pauses and you can resume it from where you left off"},{"id":"d","text":"The timer stops automatically and a manual entry is created for the elapsed time"}],"explanation":"Timers are server-side. The TimerStart timestamp is stored when you click Start, and duration is calculated from that timestamp when you stop. Closing the browser doesn't affect the running timer — it continues tracking based on the server timestamp."},{"id":"tt7","text":"You started a timer on your laptop. Will it show as running on your phone's browser too?","options":[{"id":"a","text":"No — timers are per-device and per-session"},{"id":"b","text":"Yes — SignalR broadcasts timer events via the TimerHub, so all connected clients update in real time","isCorrect":true},{"id":"c","text":"Only if you manually refresh the page on your phone"},{"id":"d","text":"Only if both devices are on the same network"}],"explanation":"The TimerHub broadcasts onTimerStartedEvent and onTimerStoppedEvent to all connected clients. When you start a timer on any device, the page header on all your open tabs and devices switches from Start Timer to Stop Timer automatically."},{"id":"tt8","text":"A manager needs to correct a time entry from last week that has the wrong duration. What is the proper process?","options":[{"id":"a","text":"Delete the entry and create a new one with the correct duration"},{"id":"b","text":"Use Admin > Time Corrections, select the entry, change the duration, and provide a reason for the correction","isCorrect":true},{"id":"c","text":"Edit the entry directly in the data table by double-clicking the duration cell"},{"id":"d","text":"Ask the employee to submit a new manual entry with the correct hours"}],"explanation":"Admin time corrections preserve an audit trail. The manager enters the corrected values and a required reason. The original values are stored in a TimeCorrectionLog entry so there is a complete record of what changed and why."},{"id":"tt9","text":"What categories are available when starting a timer or creating a manual entry?","options":[{"id":"a","text":"Only Production and Setup — other categories must be created in Admin settings"},{"id":"b","text":"None, Production, Setup, Inspection, Maintenance, Training, Meeting, Admin, Cleanup, and Other","isCorrect":true},{"id":"c","text":"Categories are not available for timers, only for manual entries"},{"id":"d","text":"The category list is custom per company — there are no default categories"}],"explanation":"Both timer and manual entry dialogs offer the same category dropdown: None (default), Production, Setup, Inspection, Maintenance, Training, Meeting, Admin, Cleanup, and Other. Categories are optional but help with reporting."},{"id":"tt10","text":"How is a time entry linked to a job for cost tracking?","options":[{"id":"a","text":"You must manually type the job number into the notes field"},{"id":"b","text":"Time entries can have a JobId foreign key — when a timer is started from a job's detail panel on the kanban board, the job link is set automatically","isCorrect":true},{"id":"c","text":"Jobs are linked after the fact by running a batch report in Admin"},{"id":"d","text":"All time entries are automatically linked to whatever job is currently selected on the kanban board"}],"explanation":"The TimeEntry entity has an optional JobId field. When you start a timer from a specific job's detail panel, the JobId is set automatically. The linked job number appears in the Job column of the time tracking table. Labor cost is then allocated to that job."},{"id":"tt11","text":"The summary line below the date filters shows '8.5 hours across 12 entries'. You change the From date to yesterday. What happens?","options":[{"id":"a","text":"Nothing — the summary only updates when you click a Refresh button"},{"id":"b","text":"The table reloads with the new date filter applied and the summary line updates to reflect the filtered results","isCorrect":true},{"id":"c","text":"The summary line stays the same but the table filters to show only yesterday's entries"},{"id":"d","text":"A confirmation dialog asks whether to apply the new filter"}],"explanation":"The date filter controls trigger an automatic reload of the entries table whenever their value changes. The summary line recalculates from the filtered entries, showing the new total hours and count."},{"id":"tt12","text":"What does the 'Type' column badge tell you about a time entry?","options":[{"id":"a","text":"Whether the entry is billable (blue) or non-billable (gray)"},{"id":"b","text":"Whether the entry was created via a live timer ('Timer' badge, blue) or logged after the fact ('Manual' badge, gray)","isCorrect":true},{"id":"c","text":"The entry's priority level — high (blue) or normal (gray)"},{"id":"d","text":"Whether the entry has been approved by a manager (blue) or is pending (gray)"}],"explanation":"The Type badge distinguishes how the time was recorded. 'Timer' (blue) means it was tracked via the Start/Stop Timer feature with precise timestamps. 'Manual' (gray) means it was entered by the user after the work was done with a specified duration."}]}"""
        });

        Log.Information("Seeded Time Tracking training modules");
    }
}
